def rolling_max(values: list[int], window: int) -> list[int]:
    if not values or window <= 0:
        return []
    if window > len(values):
        return []

    from collections import deque
    result = []
    dq = deque()

    for i in range(len(values)):
        # Remove elements from the back of the deque that are smaller than the current element
        while dq and values[dq[-1]] <= values[i]:
            dq.pop()

        # Add current element's index to the back of the deque
        dq.append(i)

        # Remove elements from the front of the deque that are outside the current window
        if dq[0] == i - window:
            dq.popleft()

        # Once the window is fully formed, record the maximum
        if i >= window - 1:
            result.append(values[dq[0]])

    return result

